diff --git a/src/orders.js b/src/orders.js
--- a/src/orders.js
+++ b/src/orders.js
@@ -5,4 +5,12 @@
+export async function loadOrders(userIds, db) {
+  const orders = [];
+  for (const id of userIds) {
+    const row = await db.query('SELECT * FROM orders WHERE user_id = $1', [id]);
+    orders.push(row);
+  }
+  return orders;
+}

